import React from "react";

export default function Sidebar() {
  return (
    <div className="w-64 h-screen bg-blue-900 text-white p-5">
      <h2 className="text-xl font-bold mb-8">CRM Dashboard</h2>
      <ul className="space-y-4">
        <li>Dashboard</li>
        <li>Contacts</li>
        <li>Lead Management</li>
        <li>Categories</li>
        <li>WhatsApp Blast</li>
        <li>SMS Blast</li>
        <li>Campaign History</li>
        <li>Reports</li>
        <li>Settings</li>
      </ul>
    </div>
  );
}
